import React, { useState, useEffect, useMemo } from 'react';

const theme = {
  bg: '#0a0a0a',
  surface: '#111111',
  surfaceAlt: '#1a1a1a',
  border: '#2a2a2a',
  text: '#fafafa',
  textSec: '#a1a1aa',
  muted: '#52525b',
  primary: '#8b5cf6',
  blue: '#38bdf8',
  yellow: '#fbbf24',
  pink: '#f472b6',
  green: '#a3e635',
  orange: '#fb923c',
  font: "'JetBrains Mono', monospace",
};

const chColors = [theme.blue, theme.pink];

const EPS = 1e-5;

const PRESETS = [
  {
    name: 'Spread',
    data: [
      [[[1.0, 2.0],[3.0, 0.5]], [[-1.0, 3.0],[0.0, 2.0]]],
      [[[2.5, 1.5],[-0.5, 1.0]], [[1.0, -2.0],[4.0, 1.0]]],
    ],
  },
  {
    name: 'Uniform',
    data: [
      [[[2.0, 2.0],[2.0, 2.0]], [[1.0, 1.0],[1.0, 1.0]]],
      [[[2.0, 2.0],[2.0, 2.0]], [[1.0, 1.0],[1.0, 1.0]]],
    ],
  },
  {
    name: 'Outlier',
    data: [
      [[[0.1, 0.2],[0.3, 0.1]], [[0.5, 0.5],[0.5, 0.5]]],
      [[[0.2, 0.1],[0.1, 5.0]], [[0.5, 0.5],[0.5, 8.0]]],
    ],
  },
];

const stepLabels = ['Input', 'Stats', 'Normalize', 'Scale+Shift'];
const stepColors = [theme.blue, theme.yellow, theme.pink, theme.green];

function valToColor(v, chIdx) {
  const base = chIdx === 0 ? [56, 189, 248] : [244, 114, 182];
  const abs = Math.min(Math.abs(v), 4);
  const intensity = 0.12 + (abs / 4) * 0.55;
  return `rgba(${base[0]},${base[1]},${base[2]},${intensity})`;
}

function Cell({ value, chIdx, highlight, glow, onClick }) {
  return (
    <div
      onClick={onClick}
      style={{
        width: 54,
        height: 54,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        background: valToColor(value, chIdx),
        borderRadius: 8,
        fontSize: 13,
        fontWeight: 600,
        color: theme.text,
        fontFamily: theme.font,
        border: highlight ? `2px solid ${chColors[chIdx]}` : '2px solid transparent',
        boxShadow: glow ? `0 0 12px ${chColors[chIdx]}44` : 'none',
        transition: 'all 0.4s ease',
        cursor: 'default',
        position: 'relative',
      }}
    >
      {value.toFixed(2)}
    </div>
  );
}

function Grid({ data, chIdx, highlight, glow }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
      {data.map((row, h) => (
        <div key={h} style={{ display: 'flex', gap: 3 }}>
          {row.map((val, w) => (
            <Cell key={w} value={val} chIdx={chIdx} highlight={highlight} glow={glow} />
          ))}
        </div>
      ))}
    </div>
  );
}

export default function App() {
  const [X, setX] = useState(PRESETS[0].data);
  const [ch, setCh] = useState(0);
  const [step, setStep] = useState(0);
  const [gamma, setGamma] = useState(1.0);
  const [beta, setBeta] = useState(0.0);
  const [playing, setPlaying] = useState(false);
  const [training, setTraining] = useState(true);

  const runMean = useMemo(() => [0.2, 0.3], []);
  const runVar = useMemo(() => [1.2, 1.5], []);

  useEffect(() => {
    if (!playing) return;
    const timer = setTimeout(() => {
      setStep(s => {
        if (s >= 3) { setPlaying(false); return 3; }
        return s + 1;
      });
    }, 1800);
    return () => clearTimeout(timer);
  }, [playing, step]);

  const channelVals = useMemo(() => {
    const vals = [];
    for (let b = 0; b < 2; b++)
      for (let h = 0; h < 2; h++)
        for (let w = 0; w < 2; w++)
          vals.push(X[b][ch][h][w]);
    return vals;
  }, [X, ch]);

  const batchMean = useMemo(() => channelVals.reduce((s, v) => s + v, 0) / channelVals.length, [channelVals]);
  const batchVar = useMemo(() => channelVals.reduce((s, v) => s + (v - batchMean) ** 2, 0) / channelVals.length, [channelVals, batchMean]);

  const usedMean = training ? batchMean : runMean[ch];
  const usedVar = training ? batchVar : runVar[ch];
  const std = Math.sqrt(usedVar + EPS);

  const getVal = (b, h, w) => {
    const raw = X[b][ch][h][w];
    if (step <= 1) return raw;
    const norm = (raw - usedMean) / std;
    if (step === 2) return norm;
    return gamma * norm + beta;
  };

  const getGrid = (b) => [
    [getVal(b, 0, 0), getVal(b, 0, 1)],
    [getVal(b, 1, 0), getVal(b, 1, 1)],
  ];

  const reset = () => {
    setStep(0);
    setPlaying(false);
    setGamma(1.0);
    setBeta(0.0);
  };

  const insights = [
    `Channel ${ch} has 8 values across 2 batches x 2x2 spatial. These will all be normalized together.`,
    training
      ? `Mean = ${batchMean.toFixed(3)}, Var = ${batchVar.toFixed(3)} computed from all 8 values in channel ${ch}.`
      : `Using running stats: mean = ${runMean[ch].toFixed(3)}, var = ${runVar[ch].toFixed(3)} (inference mode).`,
    `Each value: (x - ${usedMean.toFixed(3)}) / sqrt(${usedVar.toFixed(3)} + eps). Output has mean ~0, var ~1.`,
    `Final: gamma * normalized + beta = ${gamma.toFixed(1)} * norm + ${beta.toFixed(1)}. Scale and shift restore expressiveness.`,
  ];

  const allNorm = channelVals.map(v => (v - usedMean) / std);
  const normMean = allNorm.reduce((s,v) => s+v, 0) / allNorm.length;
  const normVar = allNorm.reduce((s,v) => s+(v-normMean)**2, 0) / allNorm.length;

  return (
    <div style={{
      maxWidth: 600,
      margin: '0 auto',
      padding: 20,
      fontFamily: theme.font,
      color: theme.text,
      background: theme.bg,
      minHeight: '100vh',
      boxSizing: 'border-box',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 14 }}>
        <div>
          <div style={{ fontSize: 18, fontWeight: 700 }}>Batch Normalization</div>
          <div style={{ fontSize: 11, color: theme.muted, marginTop: 2 }}>BCHW: B=2, C=2, H=2, W=2</div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button
            onClick={() => { if (step === 3) setStep(0); setPlaying(!playing); }}
            style={{
              background: playing ? theme.primary + '33' : theme.primary,
              color: theme.text,
              border: 'none',
              borderRadius: 8,
              padding: '6px 14px',
              fontSize: 12,
              fontFamily: theme.font,
              cursor: 'pointer',
              fontWeight: 600,
            }}
          >{playing ? 'Pause' : 'Play'}</button>
          <button
            onClick={reset}
            style={{
              background: theme.surface,
              color: theme.textSec,
              border: `1px solid ${theme.border}`,
              borderRadius: 8,
              padding: '6px 10px',
              fontSize: 12,
              fontFamily: theme.font,
              cursor: 'pointer',
            }}
          >Reset</button>
        </div>
      </div>

      {/* Channel tabs + Training toggle */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ display: 'flex', gap: 6 }}>
          {[0, 1].map(c => (
            <button
              key={c}
              onClick={() => setCh(c)}
              style={{
                background: ch === c ? chColors[c] + '22' : 'transparent',
                color: ch === c ? chColors[c] : theme.muted,
                border: `1.5px solid ${ch === c ? chColors[c] : theme.border}`,
                borderRadius: 8,
                padding: '5px 14px',
                fontSize: 12,
                fontFamily: theme.font,
                cursor: 'pointer',
                fontWeight: ch === c ? 700 : 400,
                transition: 'all 0.3s',
              }}
            >Channel {c}</button>
          ))}
        </div>
        <button
          onClick={() => setTraining(t => !t)}
          style={{
            background: training ? theme.green + '18' : theme.orange + '18',
            color: training ? theme.green : theme.orange,
            border: `1px solid ${training ? theme.green + '44' : theme.orange + '44'}`,
            borderRadius: 8,
            padding: '5px 12px',
            fontSize: 11,
            fontFamily: theme.font,
            cursor: 'pointer',
            fontWeight: 600,
          }}
        >{training ? 'Training' : 'Inference'}</button>
      </div>

      {/* Presets */}
      <div style={{ display: 'flex', gap: 6, marginBottom: 14 }}>
        <span style={{ fontSize: 10, color: theme.muted, lineHeight: '24px' }}>Data:</span>
        {PRESETS.map((p, i) => (
          <button
            key={i}
            onClick={() => { setX(p.data); setStep(0); setPlaying(false); }}
            style={{
              background: JSON.stringify(X) === JSON.stringify(p.data) ? theme.surfaceAlt : 'transparent',
              color: JSON.stringify(X) === JSON.stringify(p.data) ? theme.text : theme.muted,
              border: `1px solid ${theme.border}`,
              borderRadius: 6,
              padding: '3px 10px',
              fontSize: 10,
              fontFamily: theme.font,
              cursor: 'pointer',
            }}
          >{p.name}</button>
        ))}
      </div>

      {/* Main Visualization */}
      <div style={{
        background: theme.surface,
        borderRadius: 12,
        padding: 20,
        marginBottom: 12,
        border: `1px solid ${theme.border}`,
      }}>
        {/* Label */}
        <div style={{ fontSize: 10, color: theme.muted, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 12, textAlign: 'center' }}>
          {step <= 1 ? 'Input Values' : step === 2 ? 'Normalized Values' : 'Output (gamma * norm + beta)'}
          <span style={{ color: chColors[ch], marginLeft: 6 }}>Channel {ch}</span>
        </div>

        {/* Grids */}
        <div style={{ display: 'flex', justifyContent: 'center', gap: 40, marginBottom: 16 }}>
          {[0, 1].map(b => (
            <div key={b} style={{ textAlign: 'center' }}>
              <div style={{ fontSize: 10, color: theme.muted, marginBottom: 6 }}>Batch {b}</div>
              <Grid
                data={getGrid(b)}
                chIdx={ch}
                highlight={step >= 1}
                glow={step === 1}
              />
            </div>
          ))}
        </div>

        {/* Stats */}
        <div style={{
          display: 'flex',
          justifyContent: 'center',
          gap: 24,
          padding: '10px 0',
          opacity: step >= 1 ? 1 : 0.2,
          transition: 'opacity 0.5s',
        }}>
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 9, color: theme.muted, textTransform: 'uppercase', letterSpacing: 0.5 }}>
              {training ? 'Batch Mean' : 'Running Mean'}
            </div>
            <div style={{ fontSize: 20, fontWeight: 700, color: theme.yellow, marginTop: 2 }}>
              {usedMean.toFixed(3)}
            </div>
          </div>
          <div style={{ width: 1, background: theme.border, alignSelf: 'stretch' }} />
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 9, color: theme.muted, textTransform: 'uppercase', letterSpacing: 0.5 }}>
              {training ? 'Batch Var' : 'Running Var'}
            </div>
            <div style={{ fontSize: 20, fontWeight: 700, color: theme.yellow, marginTop: 2 }}>
              {usedVar.toFixed(3)}
            </div>
          </div>
          <div style={{ width: 1, background: theme.border, alignSelf: 'stretch' }} />
          <div style={{ textAlign: 'center' }}>
            <div style={{ fontSize: 9, color: theme.muted, textTransform: 'uppercase', letterSpacing: 0.5 }}>Std Dev</div>
            <div style={{ fontSize: 20, fontWeight: 700, color: theme.yellow, marginTop: 2 }}>
              {std.toFixed(3)}
            </div>
          </div>
        </div>

        {/* Post-norm stats */}
        {step >= 2 && (
          <div style={{
            display: 'flex',
            justifyContent: 'center',
            gap: 16,
            marginTop: 4,
            opacity: step >= 2 ? 1 : 0,
            transition: 'opacity 0.5s',
          }}>
            <span style={{ fontSize: 10, color: theme.muted }}>
              Output mean: <span style={{ color: theme.green, fontWeight: 600 }}>{(step === 2 ? normMean : gamma * normMean + beta).toFixed(4)}</span>
            </span>
            <span style={{ fontSize: 10, color: theme.muted }}>
              Output var: <span style={{ color: theme.green, fontWeight: 600 }}>{(step === 2 ? normVar : gamma * gamma * normVar).toFixed(4)}</span>
            </span>
          </div>
        )}
      </div>

      {/* Steps */}
      <div style={{ display: 'flex', gap: 4, marginBottom: 12 }}>
        {stepLabels.map((label, i) => (
          <button
            key={i}
            onClick={() => { setStep(i); setPlaying(false); }}
            style={{
              flex: 1,
              background: step === i ? stepColors[i] + '22' : theme.surface,
              color: step === i ? stepColors[i] : theme.muted,
              border: `1.5px solid ${step === i ? stepColors[i] + '66' : theme.border}`,
              borderRadius: 8,
              padding: '7px 0',
              fontSize: 11,
              fontFamily: theme.font,
              cursor: 'pointer',
              fontWeight: step === i ? 700 : 400,
              transition: 'all 0.3s',
            }}
          >{i + 1}. {label}</button>
        ))}
      </div>

      {/* Gamma/Beta sliders */}
      <div style={{
        background: theme.surface,
        borderRadius: 10,
        padding: '12px 16px',
        marginBottom: 12,
        border: `1px solid ${theme.border}`,
        opacity: step === 3 ? 1 : 0.35,
        transition: 'opacity 0.4s',
        pointerEvents: step === 3 ? 'auto' : 'none',
      }}>
        <div style={{ display: 'flex', gap: 20 }}>
          <div style={{ flex: 1 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: theme.textSec }}>gamma (scale)</span>
              <span style={{ fontSize: 13, fontWeight: 700, color: theme.green }}>{gamma.toFixed(2)}</span>
            </div>
            <input
              type="range"
              min="0.01" max="3.0" step="0.05"
              value={gamma}
              onChange={e => { setGamma(parseFloat(e.target.value)); if (step < 3) setStep(3); }}
              style={{ width: '100%', accentColor: theme.green }}
            />
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: theme.textSec }}>beta (shift)</span>
              <span style={{ fontSize: 13, fontWeight: 700, color: theme.green }}>{beta.toFixed(2)}</span>
            </div>
            <input
              type="range"
              min="-3.0" max="3.0" step="0.1"
              value={beta}
              onChange={e => { setBeta(parseFloat(e.target.value)); if (step < 3) setStep(3); }}
              style={{ width: '100%', accentColor: theme.green }}
            />
          </div>
        </div>
      </div>

      {/* Formula */}
      <div style={{
        background: theme.surface,
        borderRadius: 8,
        padding: '8px 14px',
        marginBottom: 10,
        textAlign: 'center',
        fontSize: 12,
        fontFamily: theme.font,
        color: theme.muted,
        border: `1px solid ${theme.border}`,
      }}>
        {step === 0 && (
          <span>x<sub>i,c,h,w</sub> {'->'} <span style={{color: theme.blue}}>input values</span> for channel c</span>
        )}
        {step === 1 && (
          <span>
            <span style={{color: theme.yellow}}>mean</span> = sum(x) / (B*H*W) {'  |  '}
            <span style={{color: theme.yellow}}>var</span> = sum((x - mean)<sup>2</sup>) / (B*H*W)
          </span>
        )}
        {step === 2 && (
          <span>
            <span style={{color: theme.pink}}>x_norm</span> = (x - <span style={{color: theme.yellow}}>{usedMean.toFixed(2)}</span>) / sqrt(<span style={{color: theme.yellow}}>{usedVar.toFixed(2)}</span> + eps)
          </span>
        )}
        {step === 3 && (
          <span>
            <span style={{color: theme.green}}>output</span> = <span style={{color: theme.green}}>{gamma.toFixed(1)}</span> * <span style={{color: theme.pink}}>x_norm</span> + <span style={{color: theme.green}}>{beta.toFixed(1)}</span>
          </span>
        )}
      </div>

      {/* Insight */}
      <div style={{
        background: theme.surface,
        borderRadius: 8,
        padding: '10px 14px',
        fontSize: 11,
        color: theme.textSec,
        borderLeft: `3px solid ${stepColors[step]}`,
        transition: 'border-color 0.3s',
        lineHeight: 1.6,
      }}>
        <span style={{ color: stepColors[step], fontWeight: 600 }}>
          {step === 0 ? 'Explore: ' : step === 1 ? 'Compute: ' : step === 2 ? 'Normalize: ' : 'Transform: '}
        </span>
        {insights[step]}
      </div>
    </div>
  );
}
